function to(promise) {
  return promise
    .then(data => [null, data])
    .catch(err => [err]);
}

async function getData() {
  const [error, data] = await to(fetch('https://api.example.com/data').then(res => res.json()));
  if (error) {
    console.error('Fetch error:', error);
    return;
  }
  console.log('Fetched data:', data);
}

