function isError(error: unknown): error is Error {
  return error instanceof Error;
}

try {
  throw new Error('Something went wrong');
} catch (err) {
  if (isError(err)) {
    // Now TypeScript knows err is of type Error
    console.log('Error message:', err.message);
  } else {
    // Handle unknown error types
    console.log('Unexpected error:', err);
  }
}

interface NetworkError {
  message: string;
  code: number;
  url: string;
}

function isNetworkError(error: any): error is NetworkError {
  return (
    error &&
    typeof error.message === 'string' &&
    typeof error.code === 'number' &&
    typeof error.url === 'string'
  );
}

function handleError(error: unknown) {
  if (isNetworkError(error)) {
    console.log(`Network error at ${error.url} with code ${error.code}`);
  } else if (isError(error)) {
    console.log('General error:', error.message);
  } else {
    console.log('Unknown error:', error);
  }
}

def count_up_to_five():
    for number in range(1, 6):
        yield number

# Create generator object
gen = count_up_to_five()

# Iterate over generator and print values
for value in gen:
    print(value)

def read_large_file(file_path):
    with open(file_path, 'r') as file:
        for line in file:
            yield line.strip()  # yield one line at a time

# Usage:
for line in read_large_file('large_data.txt'):
    print(line)  # Process each line without loading the whole file

def even_numbers(numbers):
    for num in numbers:
        if num % 2 == 0:
            yield num

def square_numbers(numbers):
    for num in numbers:
        yield num * num

nums = range(1, 11)
evens = even_numbers(nums)
squares = square_numbers(evens)

for value in squares:
    print(value)

